<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Mini Spreadsheet</title>
<style>
  body{font-family:Arial,sans-serif;margin:0;padding:10px;background:#f4f4f4;}
  table{border-collapse:collapse;table-layout:auto;width:100%;max-width:none;}
  th,td{border:1px solid #999;text-align:center;padding:2px;}
  th{background:#ddd;font-weight:bold;}
  input{width:100%;box-sizing:border-box;border:none;background:none;text-align:right;}
  input:focus{outline:1px solid #4a90e2;background:#fff;}
  .header{font-weight:bold;}
  #controls{margin-top:10px;}
  textarea#csv{width:100%;height:120px;margin-top:5px;font-family:monospace;}
</style>
</head>
<body>

<table id="grid">
  <thead><tr><th></th>
    <!-- Column headers A-J -->
    ${(() => {
      let cols='';
      for(let c=0;c<10;c++) cols+=`<th class="header">${String.fromCharCode(65+c)}</th>`;
      return cols;
    })()}
  </tr></thead>
  <tbody>
    ${(() => {
      let rows='';
      for(let r=1;r<=10;r++){
        rows+=`<tr><th class="header">${r}</th>`;
        for(let c=0;c<10;c++){
          const id=`cell-${String.fromCharCode(65+c)}${r}`;
          rows+=`<td><input type="text" id="${id}" data-raw="" /></td>`;
        }
        rows+='</tr>';
      }
      return rows;
    })()}
  </tbody>
</table>

<div id="controls">
  <button id="export">Export CSV</button>
  <textarea id="csv" readonly></textarea>
</div>

<script>
(() => {
  const cellIds = [];
  for(let r=1;r<=10;r++){
    for(let c=0;c<10;c++){
      const id=`cell-${String.fromCharCode(65+c)}${r}`;
      cellIds.push(id);
    }
  }

  // Utility to get cell element
  function el(id){return document.getElementById(id);}

  // Evaluate a single cell, with cycle detection
  function evaluateCell(id, stack=[]) {
    const input = el(id);
    const raw = input.dataset.raw;
    if (!raw) return '0';
    if (raw[0] !== '=') return raw; // plain text or number

    const expr = raw.slice(1);

    // Replace cell refs with their evaluated values
    const refRegex = /([A-J](?:10|[1-9]))/g;
    let replacedExpr = expr.replace(refRegex, (m) => {
      const refId = `cell-${m}`;
      if (!el(refId)) return '#ERR';
      if (stack.includes(refId)) return '#CYCLE';
      const val = evaluateCell(refId, [...stack, refId]);
      if (val === '#CYCLE' || val === '#ERR') return val;
      // If plain text non-numeric, treat as 0
      const num = parseFloat(val);
      return isNaN(num) ? '0' : num;
    });

    // Detect any remaining invalid refs
    if (/([A-J](?:10|[1-9]))/.test(replacedExpr)) return '#ERR';

    try {
      // Use Function to evaluate safely
      const result = new Function('return '+replacedExpr)();
      if (typeof result === 'number' && !isNaN(result)) return String(result);
      return '#ERR';
    } catch(e){
      return '#ERR';
    }
  }

  // Recompute all cells
  function recomputeAll() {
    const computed = {};
    cellIds.forEach(id=>{
      const val = evaluateCell(id);
      computed[id] = val;
    });
    // Update display for non-editing cells
    cellIds.forEach(id=>{
      const input=el(id);
      if (document.activeElement !== input) input.value = computed[id];
    });
  }

  // Event handlers
  cellIds.forEach(id=>{
    const input=el(id);
    input.addEventListener('focus', ()=>{
      input.value = input.dataset.raw;
    });
    input.addEventListener('blur', ()=>{
      input.dataset.raw = input.value.trim();
      recomputeAll();
    });
    input.addEventListener('keydown', e=>{
      if(e.key==='Enter'){input.blur();}
    });
  });

  // Export CSV
  document.getElementById('export').addEventListener('click',()=>{
    const rows=[];
    for(let r=1;r<=10;r++){
      const row=[];
      for(let c=0;c<10;c++){
        const id=`cell-${String.fromCharCode(65+c)}${r}`;
        const val = el(id).value;
        // Escape commas and quotes
        let cellVal = val.replace(/"/g,'""');
        if(cellVal.includes(',')||cellVal.includes('"')) cellVal='"'+cellVal+'"';
        row.push(cellVal);
      }
      rows.push(row.join(','));
    }
    document.getElementById('csv').value=rows.join('\n');
  });

  // API
  window.sheet = {
    set: (ref, txt)=>{
      const id=`cell-${ref}`;
      if(!el(id)) return;
      el(id).dataset.raw=txt.trim();
      recomputeAll();
    },
    get: (ref)=>{
      const id=`cell-${ref}`;
      if(!el(id)) return '';
      return el(id).value;
    },
    raw: (ref)=>{
      const id=`cell-${ref}`;
      if(!el(id)) return '';
      return el(id).dataset.raw||'';
    }
  };

  // Initial compute
  recomputeAll();
})();
</script>
</body>
</html>
